Here are the public test cases for feature1_1_host_range_expansion:
{
  "description": "Expands compact host pattern ranges into the concrete host aliases that a deployment target list should contain, preserving literal hostnames and reporting the resulting order and size.",
  "cases": [
    {
      "input": [
        "h[1:3]"
      ],
      "expected_output": "hosts=h1,h2,h3\ncount=3\nfirst=h1\nlast=h3\n"
    },
    {
      "input": [
        "h[01:20]"
      ],
      "expected_output": "hosts=h01,h02,h03,h04,h05,h06,h07,h08,h09,h10,h11,h12,h13,h14,h15,h16,h17,h18,h19,h20\ncount=20\nfirst=h01\nlast=h20\n"
    }
  ]
}

Here are the public test cases for feature2_1_ssh_argument_rendering:
{
  "description": "Formats transport flags and key/value options into the command-line argument string used for remote connections, while keeping default values from overriding explicit values.",
  "cases": [
    {
      "input": {
        "flags": [
          "-A",
          "-F"
        ],
        "options": {
          "Option": "Value"
        }
      },
      "expected_output": "arguments=-A -F -o Option=Value\n"
    },
    {
      "input": {
        "defaults": {
          "flags": [
            "-F"
          ],
          "options": {
            "Option": "Default"
          }
        },
        "overrides": {
          "flags": [
            "-A"
          ],
          "options": {
            "Option": "Value"
          }
        }
      },
      "expected_output": "arguments=-F -A -o Option=Value\n"
    }
  ]
}

Here are the public test cases for feature2_2_host_connection_profiles:
{
  "description": "Builds host connection profiles from aliases and connection settings, deriving the hostname, user-qualified connection target, and remote transport arguments.",
  "cases": [
    {
      "input": {
        "alias": "host",
        "values": {
          "hostname": "hostname",
          "remote_user": "remote_user",
          "port": 22,
          "config_file": "~/.ssh/config",
          "identity_file": "~/.ssh/id_rsa",
          "forward_agent": true,
          "ssh_multiplexing": true,
          "sshOptions": {
            "BatchMode": "yes",
            "Compression": "yes"
          },
          "sshFlags": [
            "-A"
          ]
        }
      },
      "expected_output": "alias=host\nhostname=hostname\nconnection=remote_user@hostname\nremote_user=remote_user\nport=22\nconfig_file=~/.ssh/config\nidentity_file=~/.ssh/id_rsa\nforward_agent=true\nssh_multiplexing=true\nssh_arguments=-A -p 22 -F ~/.ssh/config -i ~/.ssh/id_rsa -o BatchMode=yes -o Compression=yes\n"
    },
    {
      "input": {
        "alias": "host/alias",
        "values": {}
      },
      "expected_output": "alias=host/alias\nhostname=host\nconnection=host\nssh_arguments=\n"
    }
  ]
}

Here are the public test cases for feature3_1_selector_filtering:
{
  "description": "Filters an ordered host list by comma-separated label predicates, including matching every host and excluding hosts whose labels equal a given value.",
  "cases": [
    {
      "input": {
        "hosts": [
          {
            "alias": "prod",
            "labels": {
              "stage": "prod"
            }
          },
          {
            "alias": "prod/front",
            "labels": {
              "stage": "prod",
              "tier": "frontend"
            }
          },
          {
            "alias": "beta",
            "labels": {
              "stage": "beta"
            }
          }
        ],
        "selector": "stage=prod"
      },
      "expected_output": "selected=prod,prod/front\ncount=2\n"
    },
    {
      "input": {
        "hosts": [
          {
            "alias": "prod",
            "labels": {
              "stage": "prod"
            }
          },
          {
            "alias": "prod/front",
            "labels": {
              "stage": "prod",
              "tier": "frontend"
            }
          },
          {
            "alias": "beta",
            "labels": {
              "stage": "beta"
            }
          }
        ],
        "selector": "all, tier != frontend"
      },
      "expected_output": "selected=prod,beta\ncount=2\n"
    }
  ]
}

Here are the public test cases for feature4_1_template_resolution:
{
  "description": "Resolves placeholder expressions in text values using configuration entries, including default fallback values and computed entries that are evaluated to text before substitution.",
  "cases": [
    {
      "input": {
        "values": {
          "foo": "a",
          "bar": "b"
        },
        "template": "{{foo}} {{bar}}"
      },
      "expected_output": "value=a b\n"
    },
    {
      "input": {
        "values": {
          "name": "alpha"
        },
        "lookup": "path"
      },
      "expected_output": "error=missing_config_value\nkey=path\n"
    }
  ]
}

Here are the public test cases for feature4_2_inherited_configuration:
{
  "description": "Resolves configuration values through parent and root scopes, caching inherited values per child so child-specific placeholders are resolved in the requesting child context.",
  "cases": [
    {
      "input": {
        "root": {
          "global": "value from {{path}}"
        },
        "parent": {
          "path": "parent"
        },
        "children": [
          {}
        ],
        "lookups": [
          "global"
        ]
      },
      "expected_output": "child0.global=value from parent\n"
    },
    {
      "input": {
        "parent": {
          "deploy_path": "path/{{name}}"
        },
        "children": [
          {
            "name": "alpha"
          },
          {
            "name": "beta"
          }
        ],
        "lookups": [
          "deploy_path"
        ]
      },
      "expected_output": "child0.deploy_path=path/alpha\nchild1.deploy_path=path/beta\n"
    }
  ]
}

Here are the public test cases for feature4_3_array_configuration_append:
{
  "description": "Appends configuration array values, creating missing arrays, extending arrays inherited from parents, and reporting a normalized error when an append targets a scalar value.",
  "cases": [
    {
      "input": {
        "values": {
          "opt": [
            "foo",
            "bar"
          ]
        },
        "append": {
          "opt": [
            "baz"
          ]
        }
      },
      "expected_output": "opt=[\"foo\",\"bar\",\"baz\"]\n"
    },
    {
      "input": {
        "values": {
          "config": "option"
        },
        "append": {
          "config": [
            "three"
          ]
        }
      },
      "expected_output": "error=config_value_not_array\nkey=config\n"
    }
  ]
}

Here are the public test cases for feature5_1_task_execution_plan:
{
  "description": "Produces the ordered list of tasks to execute for a requested task name, expanding grouped tasks and placing before and after hooks around the target task.",
  "cases": [
    {
      "input": {
        "definitions": [
          {
            "name": "notify"
          },
          {
            "name": "info",
            "kind": "group",
            "members": [
              "notify"
            ]
          },
          {
            "name": "deploy",
            "kind": "group",
            "members": [
              "deploy:setup",
              "deploy:release"
            ]
          },
          {
            "name": "deploy:setup"
          },
          {
            "name": "deploy:release"
          }
        ],
        "before": [
          {
            "target": "deploy",
            "task": "info"
          }
        ],
        "plan": "deploy"
      },
      "expected_output": "tasks=notify,deploy:setup,deploy:release\ncount=3\n"
    },
    {
      "input": {
        "definitions": [
          {
            "name": "testTask"
          }
        ],
        "plan": "testTask2"
      },
      "expected_output": "error=item_not_found\n"
    }
  ]
}
